// Problem 012 — Fused cos/sin embedding generation (RoPE), CUDA.
//
// Shape-specialized B200 implementation with 8-freq path for memory-bound shapes:
//   * tiny shapes (B*S < 4096): proven 2-freq/thread float2 load + packed
//     __nv_bfloat162 stores, block=256.
//   * mid shapes (4096 <= B*S <= 8192): 4-freq/thread float4 load + uint2
//     packed stores, block=128.
//   * large shapes (B*S > 8192): 8-freq/thread float4x2 load + uint2 packed
//     stores, block=256 — halved grid, doubled ILP for memory-bound prefill.
//
// All paths share fp32 Cody-Waite range-reduction and __sincosf.
// The cat(freqs,freqs) duplication is done at store time: each unique
// frequency is written to column i and i+64 of the output row.
//
// Reference:
//   emb = cat(freqs, freqs)
//   cos = emb.cos() * attention_scaling -> bf16
//   sin = emb.sin() * attention_scaling -> bf16
//
// freqs is [B,S,64] fp32; outputs are [B,S,128] bf16.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <tuple>

#define HALF 64
#define FULL 128

// Cody-Waite range reduction for 2*pi, using fp32 only.
__device__ __forceinline__ float cw_reduce(float x) {
    const float INV_2PI  = 0.15915494f;
    const float TWOPI_HI = 6.28318548f;
    const float TWOPI_LO = -1.7484556e-7f;
    float k = nearbyintf(x * INV_2PI);
    float r = fmaf(-k, TWOPI_HI, x);
    return r - k * TWOPI_LO;
}

__device__ __forceinline__ unsigned int bf162_as_u32(__nv_bfloat162 v) {
    union {
        __nv_bfloat162 b;
        unsigned int u;
    } cvt;
    cvt.b = v;
    return cvt.u;
}

__device__ __forceinline__ uint2 pack_bf16x4(float v0, float v1,
                                             float v2, float v3) {
    __nv_bfloat162 lo = __floats2bfloat162_rn(v0, v1);
    __nv_bfloat162 hi = __floats2bfloat162_rn(v2, v3);
    return make_uint2(bf162_as_u32(lo), bf162_as_u32(hi));
}

__global__ void fused_rope2_kernel(const float* __restrict__ freqs,
                                   __nv_bfloat16* __restrict__ cos_out,
                                   __nv_bfloat16* __restrict__ sin_out,
                                   long n_pairs, float scale) {
    long t = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (t >= n_pairs) return;

    const float2 f = reinterpret_cast<const float2*>(freqs)[t];

    float r0 = cw_reduce(f.x);
    float r1 = cw_reduce(f.y);

    float s0, c0, s1, c1;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);

    __nv_bfloat162 cpair = __floats2bfloat162_rn(c0 * scale, c1 * scale);
    __nv_bfloat162 spair = __floats2bfloat162_rn(s0 * scale, s1 * scale);

    long two_t = t << 1;
    long row = two_t >> 6;
    long col = two_t & (HALF - 1);
    long lo = (row << 7) + col;
    long hi = lo + HALF;

    __nv_bfloat162* cptr = reinterpret_cast<__nv_bfloat162*>(cos_out);
    __nv_bfloat162* sptr = reinterpret_cast<__nv_bfloat162*>(sin_out);
    cptr[lo >> 1] = cpair;
    cptr[hi >> 1] = cpair;
    sptr[lo >> 1] = spair;
    sptr[hi >> 1] = spair;
}

__global__ void fused_rope4_kernel(const float* __restrict__ freqs,
                                   uint2* __restrict__ cos_out4,
                                   uint2* __restrict__ sin_out4,
                                   long n_quads, float scale) {
    long q = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (q >= n_quads) return;

    const float4 f = reinterpret_cast<const float4*>(freqs)[q];

    float r0 = cw_reduce(f.x);
    float r1 = cw_reduce(f.y);
    float r2 = cw_reduce(f.z);
    float r3 = cw_reduce(f.w);

    float s0, c0, s1, c1, s2, c2, s3, c3;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);
    __sincosf(r2, &s2, &c2);
    __sincosf(r3, &s3, &c3);

    uint2 cpack = pack_bf16x4(c0 * scale, c1 * scale,
                              c2 * scale, c3 * scale);
    uint2 spack = pack_bf16x4(s0 * scale, s1 * scale,
                              s2 * scale, s3 * scale);

    long row = q >> 4;
    long lane = q & 15;
    long base = (row << 5) + lane;

    cos_out4[base] = cpack;
    cos_out4[base + 16] = cpack;
    sin_out4[base] = spack;
    sin_out4[base + 16] = spack;
}

__global__ void fused_rope8_kernel(const float* __restrict__ freqs,
                                   uint2* __restrict__ cos_out8,
                                   uint2* __restrict__ sin_out8,
                                   long n_octets, float scale) {
    long q = (long)blockIdx.x * blockDim.x + threadIdx.x;
    if (q >= n_octets) return;

    // Load 2x float4 = 8 float32s per octet
    const float4* f_ptr = reinterpret_cast<const float4*>(freqs) + q * 2;
    const float4 f0 = f_ptr[0];
    const float4 f1 = f_ptr[1];

    // Range reduce all 8 frequencies
    float r0 = cw_reduce(f0.x);
    float r1 = cw_reduce(f0.y);
    float r2 = cw_reduce(f0.z);
    float r3 = cw_reduce(f0.w);
    float r4 = cw_reduce(f1.x);
    float r5 = cw_reduce(f1.y);
    float r6 = cw_reduce(f1.z);
    float r7 = cw_reduce(f1.w);

    // Compute sin/cos for all 8 values
    float s0, c0, s1, c1, s2, c2, s3, c3, s4, c4, s5, c5, s6, c6, s7, c7;
    __sincosf(r0, &s0, &c0);
    __sincosf(r1, &s1, &c1);
    __sincosf(r2, &s2, &c2);
    __sincosf(r3, &s3, &c3);
    __sincosf(r4, &s4, &c4);
    __sincosf(r5, &s5, &c5);
    __sincosf(r6, &s6, &c6);
    __sincosf(r7, &s7, &c7);

    // Pack 4 values per uint2 (2 uint2s = 8 bf16s)
    uint2 cpack0 = pack_bf16x4(c0 * scale, c1 * scale,
                               c2 * scale, c3 * scale);
    uint2 cpack1 = pack_bf16x4(c4 * scale, c5 * scale,
                               c6 * scale, c7 * scale);
    uint2 spack0 = pack_bf16x4(s0 * scale, s1 * scale,
                               s2 * scale, s3 * scale);
    uint2 spack1 = pack_bf16x4(s4 * scale, s5 * scale,
                               s6 * scale, s7 * scale);

    // Each (b,s) pair has 32 uint2s: [0-15] first half (bf16 0-63),
    // [16-31] second half (bf16 64-127, replicated). Each octet produces
    // 8 bf16s = 2 uint2s for each half.
    long row = q >> 3;      // q / 8 = which (b,s) pair
    long lane = q & 7;      // q % 8 = which octet within pair
    long base_row = (row << 5);  // row * 32 (uint2s per (b,s) pair)
    long base_first = base_row + (lane << 1);   // row*32 + lane*2 (first half)
    long base_second = base_row + 16 + (lane << 1);  // row*32 + 16 + lane*2 (second half)

    // Write 2 uint2s each (8 bf16s) to first and second halves
    cos_out8[base_first] = cpack0;
    cos_out8[base_first + 1] = cpack1;
    cos_out8[base_second] = cpack0;
    cos_out8[base_second + 1] = cpack1;

    sin_out8[base_first] = spack0;
    sin_out8[base_first + 1] = spack1;
    sin_out8[base_second] = spack0;
    sin_out8[base_second + 1] = spack1;
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs,
                                             double attention_scaling) {
    freqs = freqs.contiguous();

    const int64_t B = freqs.size(0);
    const int64_t S = freqs.size(1);
    const int64_t half = freqs.size(2);
    const int64_t full = half * 2;
    const int64_t n_freqs = B * S * half;
    const int64_t n_pairs = n_freqs >> 1;
    const int64_t n_quads = n_freqs >> 2;
    const int64_t n_octets = n_freqs >> 3;
    const int64_t rows = B * S;

    auto opts = torch::TensorOptions().dtype(torch::kBFloat16).device(freqs.device());
    auto cos_out = torch::empty({B, S, full}, opts);
    auto sin_out = torch::empty({B, S, full}, opts);

    if (n_freqs > 0) {
        const float scale = (float)attention_scaling;
        cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

        if (rows > 8192 && half == HALF) {
            // Large shapes: use 8-freq/thread for doubled ILP and halved grid
            const int block = 256;
            const int grid = (int)((n_octets + block - 1) / block);
            fused_rope8_kernel<<<grid, block, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<uint2*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<uint2*>(sin_out.data_ptr<at::BFloat16>()),
                n_octets, scale);
        } else if (rows >= 4096 && half == HALF) {
            // Mid-sized shapes: use 4-freq/thread
            const int block = (rows <= 8192) ? 128 : 256;
            const int grid = (int)((n_quads + block - 1) / block);
            fused_rope4_kernel<<<grid, block, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<uint2*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<uint2*>(sin_out.data_ptr<at::BFloat16>()),
                n_quads, scale);
        } else {
            // Tiny shapes: use proven 2-freq/thread
            const int block = 256;
            const int grid = (int)((n_pairs + block - 1) / block);
            fused_rope2_kernel<<<grid, block, 0, stream>>>(
                freqs.data_ptr<float>(),
                reinterpret_cast<__nv_bfloat16*>(cos_out.data_ptr<at::BFloat16>()),
                reinterpret_cast<__nv_bfloat16*>(sin_out.data_ptr<at::BFloat16>()),
                n_pairs, scale);
        }
    }

    return std::make_tuple(cos_out, sin_out);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "fused cos/sin RoPE embedding generation (CUDA)");
}

